diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 48055ad6ea7e..0a685263d6f6 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5774,6 +5774,7 @@ static void createUnreachableSwitchDefault(SwitchInst *Switch,
 /// Switches with 1 destination are also ignored.
 bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
                                              IRBuilder<> &Builder) {
+    
   assert(SI->getNumCases() > 1 && "Degenerate switch?");

   bool HasDefault = !SI->defaultDestUnreachable();
@@ -5802,13 +5803,85 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
     }
     return false; // More than two destinations.
   }
-  if (!DestB)
-    return false; // All destinations are the same and the default is unreachable
+  errs() << "DEBUG: DestA=" << (DestA ? DestA->getName() : "null") << ", DestB=" << (DestB ? DestB->getName() : "null") << ", HasDefault=" << HasDefault << "\\n";
+  errs() << "DEBUG: CasesA size=" << CasesA.size() << ", CasesB size=" << CasesB.size() << "\\n";
+  if (!DestB) {
+    // All explicit cases go to DestA, default goes to a different destination.
+    // Try to use range metadata to find a contiguous complement.
+    errs() << "DEBUG: turnSwitchRangeIntoICmp complement path\\n";
+    if (!HasDefault)
+      return false;
+    DestB = SI->getDefaultDest();
+    if (DestA == DestB)
+      return false;
+
+    // Try to get the value range of the switch condition.
+    std::optional<ConstantRange> CondRange;
+    if (auto *Arg = dyn_cast<Argument>(SI->getCondition()))
+      CondRange = Arg->getRange();
+    if (auto *I = dyn_cast<Instruction>(SI->getCondition())) {
+      if (auto *RangeMD = I->getMetadata(LLVMContext::MD_range))
+        CondRange = getConstantRangeFromMetadata(*RangeMD);
+      if (auto *CB = dyn_cast<CallBase>(I))
+        if (auto Range = CB->getRange())
+          CondRange = CondRange ? CondRange->intersectWith(*Range) : Range;
+    }
+
+    if (!CondRange || CondRange->isFullSet())
+      return false;
+
+    // Sort CasesA in descending order and compute the complement.
+    array_pod_sort(CasesA.begin(), CasesA.end(), constantIntSortPredicate);
+
+    // The complement of CasesA within CondRange = [L, U).
+    // CasesA is sorted descending, so iterate in reverse for ascending order.
+    APInt L = CondRange->getLower();
+    APInt U = CondRange->getUpper();
+    unsigned BW = L.getBitWidth();
+
+    // Collect the complement ranges.
+    SmallVector<std::pair<APInt, APInt>, 2> ComplementRanges;
+    APInt Cur = L;
+    for (auto *C : reverse(CasesA)) {
+      APInt Val = C->getValue();
+      if (Val.ult(Cur))
+        continue; // below current range start (shouldn't happen)
+      if (Val.uge(U))
+        continue; // outside range (shouldn't happen)
+      if (Val != Cur) {
+        // There is a gap from Cur to Val-1.
+        ComplementRanges.push_back({Cur, Val - 1});
+      }
+      Cur = Val + 1;
+      if (Cur.uge(U))
+        break;
+    }
+    if (Cur.ult(U))
+      ComplementRanges.push_back({Cur, U - 1});
+
+    // The complement must be a single contiguous range.
+    if (ComplementRanges.size() != 1)
+      return false;
+
+    APInt CompStart = ComplementRanges[0].first;
+    APInt CompEnd = ComplementRanges[0].second;
+
+    // Build CasesB from the complement range.
+    Type *CmpType = SI->getCondition()->getType();
+    CasesB.clear();
+    for (APInt V = CompStart; ; ++V) {
+      CasesB.push_back(ConstantInt::get(SI->getContext(), V));
+      if (V == CompEnd)
+        break;
+    }
+
+    assert(!CasesB.empty() && "Complement must be non-empty");
+  }

   assert(DestA && DestB &&
          "Single-destination switch should have been folded.");
   assert(DestA != DestB);
-  assert(DestB != SI->getDefaultDest());
+  // Note: DestB may be the default dest if complement was used.
   assert(!CasesB.empty() && "There must be non-default cases.");
   assert(!CasesA.empty() || HasDefault);

